use std::env;
use std::fs;
use std::process;

struct FileStats {
    lines: usize,
    words: usize,
    chars: usize,
    bytes: usize,
}

fn compute_stats(content: &str, raw_bytes: usize) -> FileStats {
    FileStats {
        lines: content.lines().count(),
        words: content.split_whitespace().count(),
        chars: content.chars().count(),
        bytes: raw_bytes,
    }
}

fn print_stats(path: &str, stats: &FileStats) {
    println!("File: {}", path);
    println!("  Lines: {}", stats.lines);
    println!("  Words: {}", stats.words);
    println!("  Chars: {}", stats.chars);
    println!("  Bytes: {}", stats.bytes);
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let show_stats = args.contains(&"--stats".to_string());
    let file_args: Vec<&String> = args[1..].iter().filter(|a| !a.starts_with("--")).collect();

    if file_args.is_empty() {
        eprintln!("Usage: filetool [--stats] <file>");
        process::exit(1);
    }

    let path = file_args[0];
    let raw = match fs::read(path) {
        Ok(bytes) => bytes,
        Err(e) => {
            eprintln!("Error: {}", e);
            process::exit(1);
        }
    };

    let content = String::from_utf8_lossy(&raw);

    if show_stats {
        let stats = compute_stats(&content, raw.len());
        print_stats(path, &stats);
    } else {
        println!("{}", content);
    }
}

use std::process::Command;
use std::fs;

#[test]
fn test_stats_output() {
    let dir = tempfile::tempdir().unwrap();
    let file = dir.path().join("test.txt");
    fs::write(&file, "hello world\nfoo bar baz\n").unwrap();

    let output = Command::new("cargo")
        .args(["run", "--", "--stats", file.to_str().unwrap()])
        .output()
        .expect("failed to run");

    let stdout = String::from_utf8(output.stdout).unwrap();
    assert!(stdout.contains("Lines: 2"));
    assert!(stdout.contains("Words: 5"));
    assert!(stdout.contains("Bytes: 23"));
}

#[test]
fn test_normal_output() {
    let dir = tempfile::tempdir().unwrap();
    let file = dir.path().join("test.txt");
    fs::write(&file, "hello").unwrap();

    let output = Command::new("cargo")
        .args(["run", "--", file.to_str().unwrap()])
        .output()
        .expect("failed to run");

    let stdout = String::from_utf8(output.stdout).unwrap();
    assert!(stdout.contains("hello"));
    assert!(!stdout.contains("Lines:"));
}
